function ee_row($id){global $db;return $db->fetch("SELECT ed.*,e.employee_no,e.full_name,e.department_code,d.nm_dept,j.job_title_code,j.job_title_name,v.employee_no verifier_no,v.full_name verifier_name FROM erp_employee_education ed JOIN erp_employee_master e ON e.id=ed.employee_id LEFT JOIN dept d ON d.kd_dept=e.department_code LEFT JOIN erp_job_title j ON j.id=e.job_title_id LEFT JOIN erp_employee_master v ON v.id=ed.verified_by_employee_id WHERE ed.id=? LIMIT 1",array((int)$id));}
function ee_payload($r){$d=(array)$r;$d['employee_text']=$r->employee_id?($r->employee_no.' - '.$r->full_name):'';$d['verified_by_text']=$r->verified_by_employee_id?($r->verifier_no.' - '.$r->verifier_name):'';return $d;}
function ee_rows($from,$to,$level,$type,$verified,$highest,$status,$kw){global $db;$w=" WHERE ed.effective_from<=? AND ed.effective_to>=? ";$p=array($to,$from);if($level!==''){$w.=" AND ed.education_level=? ";$p[]=$level;}if($type!==''){$w.=" AND ed.education_type=? ";$p[]=$type;}if($verified!==''){$w.=" AND ed.verified_status=? ";$p[]=$verified;}if($highest!==''){$w.=" AND ed.highest_education=? ";$p[]=$highest;}if($status!==''){$w.=" AND ed.status=? ";$p[]=$status;}if($kw!==''){$like='%'.$kw.'%';$w.=" AND (ed.education_no LIKE ? OR ed.institution_name LIKE ? OR ed.major LIKE ? OR e.employee_no LIKE ? OR e.full_name LIKE ? OR ed.certificate_no LIKE ?) ";array_push($p,$like,$like,$like,$like,$like,$like);}return $db->query("SELECT ed.*,e.employee_no,e.full_name,e.department_code,d.nm_dept,j.job_title_code,j.job_title_name,v.employee_no verifier_no,v.full_name verifier_name FROM erp_employee_education ed JOIN erp_employee_master e ON e.id=ed.employee_id LEFT JOIN dept d ON d.kd_dept=e.department_code LEFT JOIN erp_job_title j ON j.id=e.job_title_id LEFT JOIN erp_employee_master v ON v.id=ed.verified_by_employee_id $w ORDER BY e.employee_no,ed.highest_education DESC,ed.graduation_year DESC",$p);}
