  if($no==='')ee_json('error','Education No wajib diisi.');if(!preg_match('/^[A-Z0-9_-]{3,30}$/',$no))ee_json('error','Education No hanya boleh huruf besar, angka, underscore, atau dash.');if(!$emp)ee_json('error','Employee wajib dipilih.');if($inst==='')ee_json('error','Institution Name wajib diisi.');if(!in_array($level,$levels,true))ee_json('error','Education Level tidak valid.');if(!in_array($type,$types,true))ee_json('error','Education Type tidak valid.');if(!in_array($ver,$verified,true))ee_json('error','Verified Status tidak valid.');foreach(array($highest,$relevant) as $v){if(!in_array($v,array('Y','N'),true))ee_json('error','Flag Y/N tidak valid.');}if($from===''||$to==='')ee_json('error','Effective From/To wajib diisi.');if(strtotime($to)<strtotime($from))ee_json('error','Effective To tidak boleh sebelum Effective From.');if(!in_array($status,array('ACTIVE','INACTIVE'),true))ee_json('error','Status tidak valid.');if(!$db->fetch("SELECT id FROM erp_employee_master WHERE id=? LIMIT 1",array($emp)))ee_json('error','Employee tidak valid.');if($db->fetch("SELECT id FROM erp_employee_education WHERE education_no=? AND id<>? LIMIT 1",array($no,$id)))ee_json('error','Education No sudah digunakan.');
