case 'status':$id=(int)ee_p('id');$status=ee_c(ee_p('status'));if(!in_array($status,array('ACTIVE','INACTIVE'),true))ee_json('error','Status tidak valid.');$r=$db->fetch("SELECT * FROM erp_employee_education WHERE id=? LIMIT 1",array($id));if(!$r)ee_json('error','Employee Education tidak ditemukan.');$ok=$db->update('erp_employee_education',array('status'=>$status,'updated_by'=>$username,'updated_at'=>date('Y-m-d H:i:s')),'id',$id);if(!$ok)ee_json('error',$db->getErrorMessage()?:'Status gagal diubah.');ee_json('good','Status berhasil diubah.');
case 'detail':$r=ee_row((int)ee_p('id'));if(!$r){echo '<div class="alert alert-warning">Employee Education tidak ditemukan.</div>';break;}echo '<h3 style="margin-top:0">'.ee_h($r->education_no).' <small>'.ee_h($r->institution_name).'</small></h3><span class="label label-success">'.ee_h($r->status).'</span> <span class="label label-info">'.ee_h($r->education_level.' / '.$r->education_type).'</span> <span class="label label-primary">'.ee_h($r->verified_status).'</span><hr>';echo '<div class="row"><div class="col-sm-3"><b>'.hr_h('hr_employee', 'Employee').'</b><br>'.ee_h($r->employee_no.' - '.$r->full_name).'</div><div class="col-sm-3"><b>Major / Faculty</b><br>'.ee_h(($r->major?:'-').' / '.($r->faculty?:'-')).'</div><div class="col-sm-3"><b>'.hr_h('hr_period', 'Period').'</b><br>'.ee_h(($r->start_year?:'-').' - '.($r->graduation_year?:'-')).'</div><div class="col-sm-3"><b>Certificate</b><br>'.ee_h($r->certificate_no?:'-').'</div></div><hr>';echo '<div class="row"><div class="col-sm-3"><b>GPA / Score</b><br>'.ee_h(($r->gpa?:'-').' / '.($r->score?:'-')).'</div><div class="col-sm-3"><b>Highest</b><br>'.ee_h($r->highest_education).'</div><div class="col-sm-3"><b>Relevant</b><br>'.ee_h($r->relevant_to_position).'</div><div class="col-sm-3"><b>Verified By</b><br>'.ee_h($r->verifier_no?($r->verifier_no.' - '.$r->verifier_name):'-').'</div></div><hr><b>'.hr_h('hr_document', 'Document').'</b><p>'.ee_h($r->document_ref?:'-').'</p><b>'.hr_h('common_remarks', 'Remarks').'</b><p>'.nl2br(ee_h($r->remarks?:'-')).'</p>';break;
case 'export':
  $initial=ob_get_level();ob_start();error_reporting(E_ALL & ~E_NOTICE & ~E_WARNING & ~E_DEPRECATED & ~E_USER_DEPRECATED);require_once "../../inc/lib/PHPExcel.php";require_once "../../inc/excel_style_helper.php";PHPExcel_Shared_File::setUseUploadTempDirectory(true);$from=ee_g('tgl_awal',date('Y-01-01'));$to=ee_g('tgl_akhir','9999-12-31');$rows=ee_rows($from,$to,ee_g('education_level',''),ee_g('education_type',''),ee_g('verified_status',''),ee_g('highest_education',''),ee_g('status',''),ee_g('keyword',''));$excel=new PHPExcel();$sheet=$excel->setActiveSheetIndex(0);$sheet->setTitle(erp_export_sheet_title('Education'));$heads=array(erp_export_label("No"),erp_export_label("Education No"),erp_export_label("Employee"),erp_export_label("Level"),erp_export_label("Type"),erp_export_label("Institution"),erp_export_label("Major"),erp_export_label("Faculty"),erp_export_label("City"),erp_export_label("Country"),erp_export_label("Start"),erp_export_label("Graduation"),erp_export_label("Certificate"),erp_export_label("GPA"),erp_export_label("Score"),erp_export_label("Highest"),erp_export_label("Relevant"),erp_export_label("Verified"),erp_export_label("Verifier"),erp_export_label("Effective"),erp_export_label("Status"),erp_export_label("Document"),erp_export_label("SAP Ref"),erp_export_label("Updated By"));foreach($heads as $i=>$h)$sheet->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).'4',$h);$rnum=5;$n=1;foreach($rows as $r){$vals=array($n++,$r->education_no,$r->employee_no.' - '.$r->full_name,$r->education_level,$r->education_type,$r->institution_name,$r->major,$r->faculty,$r->city,$r->country,$r->start_year,$r->graduation_year,$r->certificate_no,$r->gpa,$r->score,$r->highest_education,$r->relevant_to_position,$r->verified_status,$r->verifier_no.' - '.$r->verifier_name,$r->effective_from.' s/d '.$r->effective_to,$r->status,$r->document_ref,$r->sap_reference,$r->updated_by?:$r->created_by);foreach($vals as $i=>$v)$sheet->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i